"""Run from your insightforge project root:  python3 install_stage7.py

Also adds the `eval` target to your Makefile if missing.
"""
import base64
from pathlib import Path
ROOT = Path(__file__).parent
FILES = {
  "backend/app/evaluation/benchmark.yaml": "",
  "backend/app/evaluation/scorer.py": "",
  "backend/app/evaluation/runner.py": "",
  "backend/tests/test_evaluation_scorer.py": ""
}
for rel, b64 in FILES.items():
    p = ROOT / rel
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_bytes(base64.b64decode(b64))
    print(f"  wrote {rel}")

mk = ROOT / "Makefile"
if mk.exists() and "eval:" not in mk.read_text():
    mk.write_text(mk.read_text() + "\n\neval:\n\tPYTHONPATH=backend .venv/bin/python -m app.evaluation.runner\n")
    print("  added eval target to Makefile")
print("\nDone! Now run: make test")